using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Forms;

namespace sv_d86040f8962445548c5a5206b2ff6eb7.Components;

public class CustomValidator : ComponentBase
{
    [CascadingParameter]
    private EditContext? EditContext { get; set; }

    private ValidationMessageStore? messageStore;

    protected override void OnInitialized()
    {
        messageStore = new ValidationMessageStore(EditContext!);
        EditContext!.OnValidationRequested += (s, e) => messageStore.Clear();
        EditContext!.OnFieldChanged += (s, e) => messageStore.Clear(e.FieldIdentifier);
    }

    public void DisplayErrors(Dictionary<string, List<string>> errors)
    {
        foreach (var (field, messages) in errors)
        {
            foreach (var message in messages)
            {
                messageStore!.Add(EditContext!.Field(field), message);
            }
        }
        EditContext!.NotifyValidationStateChanged();
    }

    public void ClearErrors()
    {
        messageStore?.Clear();
        EditContext?.NotifyValidationStateChanged();
    }
}

@page "/book-appointment"
@rendermode InteractiveServer
@using sv_d86040f8962445548c5a5206b2ff6eb7.Services
@inject AppointmentService AppointmentService

<PageTitle>Book Appointment</PageTitle>

<h3>Book a Medical Appointment</h3>

<EditForm EditContext="editContext" OnValidSubmit="HandleSubmit" FormName="book-appointment">
    <DataAnnotationsValidator />
    <CustomValidator @ref="customValidator" />

    @* ── STEP 1 ── *@
    <fieldset>
        <legend>Patient Information</legend>

        <div class="mb-3">
            <label class="form-label" for="patientName">Patient Name</label>
            <InputText id="patientName" class="form-control" @bind-Value="Model.PatientName" />
            <ValidationMessage For="() => Model.PatientName" />
        </div>

        <div class="mb-3">
            <label class="form-label" for="email">Email</label>
            <InputText id="email" class="form-control" @bind-Value="Model.Email" />
            <ValidationMessage For="() => Model.Email" />
        </div>

        <div class="mb-3">
            <label class="form-label" for="phone">Phone</label>
            <InputText id="phone" class="form-control" @bind-Value="Model.Phone" />
            <ValidationMessage For="() => Model.Phone" />
        </div>

        <div class="mb-3">
            <label class="form-label" for="insurance">Insurance Provider</label>
            <InputSelect id="insurance" class="form-control" @bind-Value="Model.InsuranceProvider">
                <option value="">-- Select --</option>
                <option value="Aetna">Aetna</option>
                <option value="BlueCross">BlueCross</option>
                <option value="Cigna">Cigna</option>
                <option value="UnitedHealth">UnitedHealth</option>
                <option value="None">None</option>
            </InputSelect>
            <ValidationMessage For="() => Model.InsuranceProvider" />
        </div>
    </fieldset>

    @if (!showStep2)
    {
        <button type="button" class="btn btn-primary" @onclick="GoToStep2">
            Next
        </button>
    }

    @* ── STEP 2 ── *@
    @if (showStep2)
    {
        <fieldset class="mt-4">
            <legend>Appointment Details</legend>

            <div class="mb-3">
                <label class="form-label" for="doctor">Preferred Doctor</label>
                <InputSelect id="doctor" class="form-control" @bind-Value="Model.Doctor"
                             @bind-Value:after="OnDoctorChanged">
                    <option value="">-- Select --</option>
                    @foreach (var doc in doctors)
                    {
                        <option value="@doc">@doc</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => Model.Doctor" />
            </div>

            <div class="mb-3">
                <label class="form-label" for="date">Date</label>
                <InputDate id="date" class="form-control" @bind-Value="Model.AppointmentDate"
                           @bind-Value:after="OnDateChanged" />
                <ValidationMessage For="() => Model.AppointmentDate" />
                @if (Model.AppointmentDate is not null && Model.AppointmentDate <= DateOnly.FromDateTime(DateTime.Today))
                {
                    <div class="validation-message">Appointment date must be in the future.</div>
                }
            </div>

            <div class="mb-3">
                <label class="form-label" for="timeSlot">Time Slot</label>
                <InputSelect id="timeSlot" class="form-control" @bind-Value="Model.TimeSlot">
                    <option value="">-- Select --</option>
                    @foreach (var slot in availableSlots)
                    {
                        <option value="@slot">@slot</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => Model.TimeSlot" />
            </div>

            <div class="mb-3">
                <label class="form-label" for="reason">Reason for Visit</label>
                <InputTextArea id="reason" class="form-control" @bind-Value="Model.Reason" rows="3" />
                <ValidationMessage For="() => Model.Reason" />
                <small class="text-muted">@((Model.Reason?.Length ?? 0))/500 characters</small>
            </div>

            <div class="d-flex gap-2">
                <button type="button" class="btn btn-secondary" @onclick="BackToStep1">
                    Back
                </button>
                <button type="button" class="btn btn-info" @onclick="CheckAvailability" disabled="@isChecking">
                    @(isChecking ? "Checking..." : "Check Availability")
                </button>
                @if (availabilityChecked)
                {
                    <button type="submit" class="btn btn-success" disabled="@isSubmitting">
                        @(isSubmitting ? "Booking..." : "Book Appointment")
                    </button>
                }
            </div>
        </fieldset>
    }
</EditForm>

@if (bookingConfirmed)
{
    <div class="alert alert-success mt-4">
        Appointment booked successfully for <strong>@Model.PatientName</strong>
        with <strong>@Model.Doctor</strong> on @Model.AppointmentDate?.ToString("MMMM d, yyyy")
        at @Model.TimeSlot.
    </div>
}

@code {
    private AppointmentModel Model = new();
    private EditContext editContext = null!;
    private CustomValidator? customValidator;

    private List<string> doctors = [];
    private List<string> availableSlots = [];

    private bool showStep2;
    private bool isChecking;
    private bool isSubmitting;
    private bool availabilityChecked;
    private bool bookingConfirmed;

    private static readonly string[] Step1Fields =
        [nameof(AppointmentModel.PatientName), nameof(AppointmentModel.Email),
         nameof(AppointmentModel.Phone), nameof(AppointmentModel.InsuranceProvider)];

    protected override async Task OnInitializedAsync()
    {
        editContext = new EditContext(Model);
        doctors = await AppointmentService.GetDoctorsAsync();
    }

    private void GoToStep2()
    {
        // Validate only Step 1 fields
        var isValid = true;
        foreach (var field in Step1Fields)
        {
            var fi = editContext.Field(field);
            editContext.NotifyFieldChanged(fi);
        }

        editContext.Validate();

        // Check if any Step 1 fields have errors
        foreach (var field in Step1Fields)
        {
            if (editContext.GetValidationMessages(editContext.Field(field)).Any())
            {
                isValid = false;
                break;
            }
        }

        if (isValid)
        {
            showStep2 = true;
        }
    }

    private void BackToStep1()
    {
        showStep2 = false;
        availabilityChecked = false;
    }

    private async Task OnDoctorChanged()
    {
        availabilityChecked = false;
        Model.TimeSlot = null;
        await LoadSlots();
    }

    private async Task OnDateChanged()
    {
        availabilityChecked = false;
        Model.TimeSlot = null;
        await LoadSlots();
    }

    private async Task LoadSlots()
    {
        if (!string.IsNullOrEmpty(Model.Doctor) && Model.AppointmentDate.HasValue)
        {
            availableSlots = await AppointmentService.GetAvailableSlotsAsync(
                Model.Doctor, Model.AppointmentDate.Value);
        }
        else
        {
            availableSlots = [];
        }
    }

    private async Task CheckAvailability()
    {
        customValidator?.ClearErrors();
        availabilityChecked = false;

        // Validate step 2 fields locally first
        editContext.Validate();

        var step2Fields = new[]
        {
            nameof(AppointmentModel.Doctor), nameof(AppointmentModel.AppointmentDate),
            nameof(AppointmentModel.TimeSlot), nameof(AppointmentModel.Reason)
        };

        foreach (var field in step2Fields)
        {
            if (editContext.GetValidationMessages(editContext.Field(field)).Any())
            {
                return;
            }
        }

        if (Model.AppointmentDate is not null && Model.AppointmentDate <= DateOnly.FromDateTime(DateTime.Today))
        {
            return;
        }

        isChecking = true;
        try
        {
            var errors = await AppointmentService.ValidatePatientAsync(
                Model.Email!, Model.InsuranceProvider!, Model.Doctor!, Model.TimeSlot!);

            if (errors.Count > 0)
            {
                customValidator!.DisplayErrors(errors);
                return;
            }

            availabilityChecked = true;
        }
        finally
        {
            isChecking = false;
        }
    }

    private async Task HandleSubmit()
    {
        if (!availabilityChecked)
        {
            return;
        }

        if (Model.AppointmentDate is not null && Model.AppointmentDate <= DateOnly.FromDateTime(DateTime.Today))
        {
            return;
        }

        isSubmitting = true;
        try
        {
            // Re-validate server-side before final booking
            var errors = await AppointmentService.ValidatePatientAsync(
                Model.Email!, Model.InsuranceProvider!, Model.Doctor!, Model.TimeSlot!);

            if (errors.Count > 0)
            {
                customValidator!.DisplayErrors(errors);
                availabilityChecked = false;
                return;
            }

            // Simulate booking
            await Task.Delay(500);
            bookingConfirmed = true;
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

